export function toShort(i){const res=Buffer.allocUnsafe(2);res.writeUInt16LE(i);return res}export function toInt(i){const res=Buffer.allocUnsafe(4);res.writeUInt32LE(i);return res}export function toFloat(i){const res=Buffer.allocUnsafe(4);res.writeFloatLE(i);return res}export function toBoolean(val){return toFloat(val?1:0)}Buffer.prototype.matches=function(buffer){return buffer.length>=this.length&&this.compare(buffer,0,this.length)===0};